func duckdb_parameter_name_string(
	prepared_statement duckdb_prepared_statement,
	index uint64,
) string {
	rawPtr := duckdb_parameter_name(
		prepared_statement,
		index,
	)
	result := gostring(rawPtr)
	if rawPtr != 0 {
		duckdb_free(rawPtr)
	}
	return result
}
func duckdb_prepared_statement_column_name_string(
	prepared_statement duckdb_prepared_statement,
	col_idx uint64,
) string {
	rawPtr := duckdb_prepared_statement_column_name(
		prepared_statement,
		col_idx,
	)
	result := gostring(rawPtr)
	if rawPtr != 0 {
		duckdb_free(rawPtr)
	}
	return result
}

func gostring(ptr uintptr) string {
	if ptr == 0 {
		return ""
	}
	p := *(*unsafe.Pointer)(unsafe.Pointer(&ptr))
	var n int
	for *(*byte)(unsafe.Add(p, n)) != 0 {
		n++
	}
	return strings.Clone(unsafe.String((*byte)(p), n))
}

